const gradesDataArr=[['Matemática',3.3,5],['Inglês',3.3,5],['Projeto',3.3,5],['Ciências',5.0,4],['Arte',5.0,3],['Português',6.7,2],['Geografia',6.0,1],['História',7.3,1]];
const icons={'Matemática':'🧮','Inglês':'🇺🇸','Projeto':'💡','Catecismo':'✝️','Latim':'🏛️','Ed. Financeira':'💰','Português':'📝','Ciências':'🔬','Geografia':'🌎','História':'🏛️','Arte':'🎨'};
const curriculum={Matemática:['Porcentagem','Equações','Funções','Estatística','Geometria'],Português:['Interpretação textual','Produção textual'],Ciências:['Genética','Ecologia','Corpo humano'],História:['República','Guerras Mundiais'],Geografia:['Globalização','Geopolítica'],Inglês:['Reading','Vocabulário','Verbos'],Arte:['Artes visuais','Música'],Projeto:['Pesquisa','Apresentação oral']};
const plans={1:['Segunda-feira','Gramática','gram',[['Português','Interpretação e gramática'],['Inglês','Vocabulário e reading'],['Rosetta Stone','20 minutos'],['Latim','Oração do mês'],['Exercício','Quiz de gramática']]],2:['Terça-feira','Dialética','dial',[['Matemática','Porcentagem ou equações'],['Ciências','Genética ou ecologia'],['Educação Financeira','Problema prático'],['Revisão','Questões erradas']]],3:['Quarta-feira','Retórica','rhet',[['Projeto','Pesquisa'],['Português','Texto curto'],['Apresentação oral','Explicar ao responsável'],['Inglês','Frases simples']]],4:['Quinta-feira','Quadrivium','quad',[['Geometria','Número no espaço'],['Geografia','Mapas'],['Arte','Forma e proporção'],['Astronomia','Tempo e movimento']]],5:['Sexta-feira','Síntese','syn',[['Revisão geral','Matemática, Inglês e Projeto'],['Boss Battle','20 questões'],['Organização','Material e pendências']]],6:['Sábado','Catecismo','cat',[['Catecismo','Leitura anual'],['Perguntas','3 perguntas'],['Oração','Credo ou Sinal da Cruz']]],0:['Domingo','Vida Cristã','cat',[['Missa','Participar'],['Revisão dominical','Relembrar leitura'],['Orações','Pai Nosso e Ave Maria']]]};
const qs={Matemática:[['15% de 200 é:',['15','20','30','50'],2,'15% = 0,15; 0,15 × 200 = 30.']],Inglês:[['Book significa:',['Mesa','Livro','Casa','Caneta'],1,'Book = livro.']],Catecismo:[['As partes principais da Doutrina Cristã são:',['Credo, Padre-Nosso, Mandamentos e Sacramentos','Somente Latim','Somente História'],0,'São quatro partes principais.']],Latim:[['Cognoscere significa:',['Conhecer','Amar','Servir'],0,'Cognoscere = conhecer.']]};
let state=JSON.parse(localStorage.getItem('aguiaV15')||'{"checked":{},"money":{},"xp":0,"cateDone":{},"catePage":0,"cateXP":0,"cateFavorites":[],"piggy":{"free":0,"saved":0,"charity":0},"aiPlan":""}');
function save(){localStorage.setItem('aguiaV15',JSON.stringify(state))}
function iso(d){return d.toISOString().slice(0,10)} function today(){return iso(new Date())} function money(n){return 'R$ '+Number(n).toFixed(0)} function plan(d){return plans[d.getDay()]} function tid(d,i){return iso(d)+'-'+i}
function stats(d=new Date()){let p=plan(d),done=0;p[3].forEach((_,i)=>{if(state.checked[tid(d,i)])done++});return{done,total:p[3].length,pct:Math.round(done/p[3].length*100),complete:done===p[3].length}}
function criticalSubject(){return gradesDataArr.slice().sort((a,b)=>a[1]-b[1])[0][0]} function weekMoneyTotal(){return Object.values(state.money).reduce((a,b)=>a+b,0)}
function switchTab(tab){document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));document.getElementById(tab).classList.add('active');document.querySelectorAll('[data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));renderAll()}
enter.onclick=()=>{if(pass.value===PASSWORD){localStorage.setItem('unlockedV15','yes');lock.classList.add('hidden');app.classList.remove('hidden')}else alert('Senha incorreta')};if(localStorage.getItem('unlockedV15')==='yes'){lock.classList.add('hidden');app.classList.remove('hidden')}
function saturdaysOfYear(){let y=new Date().getFullYear(),d=new Date(y,0,1),arr=[];while(d.getFullYear()===y){if(d.getDay()===6)arr.push(new Date(d));d.setDate(d.getDate()+1)}return arr.slice(0,52)}
function cateWeekIndex(date=new Date()){let sats=saturdaysOfYear();let idx=sats.findIndex(s=>iso(s)>=iso(date));return idx<0?51:idx}
function cateDoneCount(){return Object.keys(state.cateDone).length}
function renderMission(){let d=new Date(),p=plan(d),s=stats(d);todayTitle.textContent=p[0]+' — '+p[1];tasks.innerHTML=p[3].map((t,i)=>`<label class="task"><input type="checkbox" data-id="${tid(d,i)}" ${state.checked[tid(d,i)]?'checked':''}><span><b>${t[0]}</b><small>${t[1]}</small></span></label>`).join('');dayPct.textContent=s.pct+'%';dayBar.style.width=s.pct+'%';todayMoney.textContent=state.money[today()]?money(10):'R$ 0';missionText.textContent=s.complete?'Missão completa. Peça aprovação.':'Complete tudo para liberar R$ 10.';tasksDone.textContent=s.done+'/'+s.total}
function renderEagleMessage(){let s=stats(),p=plan(new Date());eagleMessage.textContent=new Date().getDay()===6?'Hoje é sábado: abra a leitura completa do Catecismo.':`Hoje é dia de ${p[1]}. Faltam ${Math.max(0,s.total-s.done)} tarefa(s).`}
function generateAIPlan(){let c=criticalSubject(),idx=state.catePage||cateWeekIndex(),theme=cateLessons[idx].theme;let tomorrow=new Date();tomorrow.setDate(tomorrow.getDate()+1);let tp=plan(tomorrow);state.aiPlan=`Projeto Águia V15\n\nPrioridade escolar: ${c}\nCatecismo: ${cateDoneCount()}/52 sábados concluídos\nTema atual: ${theme}\n\nAmanhã (${tp[0]} — ${tp[1]}):\n- ${tp[3].map(x=>x[0]).join('\n- ')}\n\nCrie 5 exercícios simples para João Miguel: 3 sobre ${c} e 2 sobre o tema do Catecismo (${theme}).`;save()}
function renderAI(){if(!state.aiPlan)generateAIPlan();aiPrompt.value=state.aiPlan;tomorrowPlan.innerHTML=`<div class="details">${state.aiPlan.replaceAll('\n','<br>')}</div>`;critical.textContent=criticalSubject()}
function renderChallenge(){let all=Object.entries(qs).flatMap(([s,a])=>a.map(q=>({s,q})));let x=all[new Date().getDate()%all.length];challenge.innerHTML=`<p><b>${x.s}</b></p><p>${x.q[0]}</p>`+x.q[1].map((a,i)=>`<button class="answer" data-sub="${x.s}" data-i="${i}">${a}</button>`).join('')+`<div id="fb" class="feedback hidden"></div>`}
function renderAnnual(){let y=new Date().getFullYear();let names=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];annualCalendar.innerHTML=`<div class="annual-grid">`+names.map((name,m)=>{let first=new Date(y,m,1),last=new Date(y,m+1,0);let heads=['D','S','T','Q','Q','S','S'].map(x=>`<div class="head">${x}</div>`).join('');let cells='';for(let i=0;i<first.getDay();i++)cells+='<button class="mini-day empty"></button>';for(let day=1;day<=last.getDate();day++){let d=new Date(y,m,day),p=plan(d),key=iso(d),done=state.cateDone[key]?' ✅':'';cells+=`<button class="mini-day ${p[2]}" data-annual="${key}">${day}${done}</button>`}return `<div class="month-card"><h3>${name}</h3><div class="mini-grid">${heads}${cells}</div></div>`}).join('')+`</div>`}
function describeDate(key){let d=new Date(key+'T00:00:00'),p=plan(d),s=stats(d);let extra=d.getDay()===6?`<br><button data-open-date-cate="${key}">Abrir leitura completa do Catecismo</button>`:'';annualDetails.innerHTML=`<b>${p[0]} — ${key}</b><br><small>Eixo: ${p[1]} • ${s.done}/${s.total} tarefas</small>${extra}<ul>${p[3].map(t=>`<li><b>${t[0]}</b>: ${t[1]}</li>`).join('')}</ul>`}
function renderCateReader(){let i=state.catePage||0,l=cateLessons[i],sats=saturdaysOfYear(),key=iso(sats[i]);let fav=state.cateFavorites.includes(i);cateReader.innerHTML=`<div class="reader"><h3>${l.theme}</h3><small>Sábado: ${key} • semana ${i+1} de 52</small><div class="reader-body">${l.html}</div><div class="reader-controls"><button id="prevCate" class="secondary">◀ Anterior</button><button id="nextCate">Próxima ▶</button><button id="favCate" class="secondary">${fav?'★ Remover favorito':'☆ Favoritar'}</button><button id="markCate">☑ Concluir leitura</button></div></div>`}
function renderCatechism(){let done=cateDoneCount(),pct=Math.round(done/52*100);cateProgress.textContent=pct+'%';cateDone.textContent=done+'/52';cateXP.textContent=state.cateXP+' XP';cateBar.style.width=pct+'%';cateMedal.textContent=done>=52?'Águia da Fé':done>=40?'Guardião da Doutrina':done>=25?'Discípulo de São Pio X':done>=10?'Pequeno Catequista':'Primeiro Sábado';renderCateReader();renderCateSearch();renderCateFavorites();let current=state.catePage||cateWeekIndex();cateSchedule.innerHTML=saturdaysOfYear().map((d,i)=>{let key=iso(d),done=state.cateDone[key];return`<div class="cate-week ${done?'done':''} ${i===current?'current':''}"><b>${i+1}. ${key}</b><br><small>${cateLessons[i].theme}</small><br><button data-open-cate="${i}">Abrir lição</button></div>`}).join('');parentCatechism.innerHTML=`<div class="details"><b>${done}/52 sábados</b><br><small>${pct}% concluído • ${state.cateXP} XP</small></div>`}
function renderCateSearch(){let q=(cateSearch.value||'').toLowerCase();if(!q){cateSearchResults.innerHTML='<p class="muted">Digite uma palavra para buscar nos temas.</p>';return}let results=cateLessons.map((l,i)=>({t:l.theme,i})).filter(x=>x.t.toLowerCase().includes(q));cateSearchResults.innerHTML=results.length?results.map(r=>`<div class="search-result"><b>${r.i+1}. ${r.t}</b><br><button data-open-cate="${r.i}">Abrir</button></div>`).join(''):'<p class="muted">Nenhum resultado.</p>'}
function renderCateFavorites(){cateFavorites.innerHTML=state.cateFavorites.length?state.cateFavorites.map(i=>`<div class="favorite"><b>${i+1}. ${cateLessons[i].theme}</b><br><button data-open-cate="${i}">Abrir</button></div>`).join(''):'<p class="muted">Nenhum favorito ainda.</p>'}
function renderAcademy(){curriculum.innerHTML=Object.entries(curriculum).map(([s,it])=>`<div class="item"><b>${icons[s]||'📚'} ${s}</b><br><small>${it.join(' • ')}</small></div>`).join('');subjects.innerHTML=Object.keys(qs).map(s=>`<button class="subject" data-subject="${s}">${icons[s]||'📚'} ${s}</button>`).join('')}
function gradesData(){return gradesDataArr.map(g=>`<div class="grade"><b>${g[0]}</b><br><small>Nota ${g[1].toFixed(1)} • peso ${g[2]}</small></div>`).join('')}
function approve(){let s=stats();if(!s.complete){approval.textContent='A missão ainda não está completa.';return}if(state.money[today()]){approval.textContent='Missão já aprovada hoje.';return}state.money[today()]=10;state.xp+=10;state.piggy.free+=7;state.piggy.saved+=2;state.piggy.charity+=1;state.aiPlan='';save();approval.textContent='🦅 Missão aprovada. R$ 10 liberados.';renderAll()}
function renderAll(){renderMission();renderEagleMessage();renderAI();renderChallenge();renderAnnual();renderCatechism();renderAcademy();grades.innerHTML=gradesData();weekMoney.textContent=money(weekMoneyTotal());xp.textContent=state.xp+' XP'}
document.addEventListener('change',e=>{if(e.target.matches('#tasks input')){state.checked[e.target.dataset.id]=e.target.checked;state.aiPlan='';save();renderAll()}});
document.addEventListener('input',e=>{if(e.target.id==='cateSearch')renderCateSearch()});
document.addEventListener('click',e=>{if(e.target.matches('[data-tab]'))switchTab(e.target.dataset.tab);if(e.target.id==='goParent')switchTab('parent');if(e.target.id==='approve')approve();if(e.target.id==='runAI'){generateAIPlan();renderAll()}if(e.target.id==='copyAIPrompt'){aiPrompt.select();document.execCommand('copy');alert('Relatório copiado.')}if(e.target.matches('[data-annual]'))describeDate(e.target.dataset.annual);if(e.target.matches('[data-open-date-cate]')){let key=e.target.dataset.openDateCate;let idx=saturdaysOfYear().findIndex(d=>iso(d)===key);state.catePage=idx>=0?idx:cateWeekIndex(new Date(key+'T00:00:00'));save();switchTab('catechism')}if(e.target.matches('[data-open-cate]')){state.catePage=Number(e.target.dataset.openCate);state.aiPlan='';save();switchTab('catechism')}if(e.target.matches('[data-subject]')){let sub=e.target.dataset.subject,q=qs[sub][0];quiz.innerHTML=`<h3>${icons[sub]||'📚'} ${sub}</h3><p>${q[0]}</p>`+q[1].map((a,i)=>`<button class="answer" data-sub="${sub}" data-i="${i}">${a}</button>`).join('')+`<div id="qfb" class="feedback hidden"></div>`}if(e.target.matches('.answer')){let sub=e.target.dataset.sub,q=qs[sub][0],ok=Number(e.target.dataset.i)===q[2];e.target.classList.add(ok?'correct':'wrong');state.xp+=ok?5:0;let fb=document.getElementById('qfb')||document.getElementById('fb');fb.classList.remove('hidden');fb.textContent=ok?'✅ Correto! +5 XP':'❌ '+q[3];state.aiPlan='';save();renderAll()}if(e.target.id==='continueCatechism'){state.catePage=cateWeekIndex();save();switchTab('catechism')}if(e.target.id==='prevCate'){state.catePage=Math.max(0,(state.catePage||0)-1);state.aiPlan='';save();renderAll()}if(e.target.id==='nextCate'){state.catePage=Math.min(51,(state.catePage||0)+1);state.aiPlan='';save();renderAll()}if(e.target.id==='favCate'){let i=state.catePage||0;state.cateFavorites=state.cateFavorites.includes(i)?state.cateFavorites.filter(x=>x!==i):[...state.cateFavorites,i];save();renderAll()}if(e.target.id==='markCate'){let i=state.catePage||0,key=iso(saturdaysOfYear()[i]);if(!state.cateDone[key]){state.cateDone[key]=true;state.cateXP+=10;state.xp+=10;state.aiPlan='';save()}renderAll()}if(e.target.id==='export'){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='projeto-aguia-v15-progresso.json';a.click()}if(e.target.id==='logout'){localStorage.removeItem('unlockedV15');location.reload()}});
if('serviceWorker' in navigator)navigator.serviceWorker.register('service-worker.js');
renderAll();
